VALUES
  ('elementary-6f0ba476-moex-00204', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-113-b3f42868', 'sub-elementary-6f0ba476-01', NULL, 'single_choice', '綠島某民宿業者捕殺保育魚類龍王鯛，引發民眾強力譴責，海洋委員會海巡署將民宿業者移送法辦。依財 貨的性質來分類，保育魚類龍王鯛屬於下列何者？', '["不具獨享性且無排他性", "具獨享性且具排他性", "不具獨享性但具排他性", "具獨享性但無排他性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:38+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "507", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00205', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-113-b3f42868', 'sub-elementary-6f0ba476-01', NULL, 'single_choice', '一般認為醫生享有較高的社會地位，而街友則屬於社會的底層。若以功能論與衝突論解釋兩者社會地位的 差異，下列敘述何者正確？', '["功能論認為醫生具醫療專業，替代性較小，所以受社會的重視", "功能論認為醫生因為掌握較多資源而享有較高地位，並非其能力較強", "衝突論認為街友社會地位較低乃因能力不足，而非擁有較少社會資源", "衝突論認為街友的存在可創造社工人員等工作機會，故有其存在功能"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:38+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "507", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00206', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-113-b3f42868', 'sub-elementary-6f0ba476-01', NULL, 'single_choice', '2019 年夏天，日本捲起臺灣珍珠奶茶的旋風，除了飲品外，從瑞士捲、巧克力，甚至是拉麵、壽司等食 物，都有珍珠奶茶口味。此外，在網路社群上更出現了新興網路用語，如：「珍珠活」，指喝著有加珍珠 的行為活動、「珍珠巡禮」，意思是走訪各大珍珠奶茶名店。下列何者最適合用來形容前述現象？', '["是另類全球化的結果", "網路社群的新興用語反映次文化", "珍珠奶茶文化屬於精緻文化", "此為強勢文化主導的文化交流"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:38+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "507", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00207', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-113-b3f42868', 'sub-elementary-6f0ba476-01', NULL, 'single_choice', '美國倫理學家約翰‧羅爾斯（JohnRawls，1921-2002）最著名的正義論，認為正義是社會制度的主要美德。 他主張制度運作須符合以下兩個正義原則：均等自由原則及差異原則。下列那項政策最能實現羅爾斯差異 原則之精神？', '["經由大法官釋憲，同性戀者可以享有結婚的權利", "身心障礙者若闖紅燈，警察在確認身分後不開罰", "外籍人士在我國工作者，可以免費施打肺炎疫苗", "原住民族學生，符合規定者升學時享有加分措施"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:38+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "507", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00208', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-113-b3f42868', 'sub-elementary-6f0ba476-01', NULL, 'single_choice', '主流學說認為國家構成要件有四元素。下列敘述何者正確？', '["領土的範疇包含國籍船舶與航空器", "一國之人民須以取得參政權為資格", "主權運作係針對國民之各種治理行為", "政府須通過選舉產生才具有治理正當性"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:38+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "507", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00209', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-113-b3f42868', 'sub-elementary-6f0ba476-01', NULL, 'single_choice', '依據公務人員行政中立法，公務人員從事下列何種行為必然違反行政中立之規範？', '["公開為作為議員候選人之配偶拉票", "參與直轄市市長候選人之造勢活動", "發起反統或反獨之政黨集會遊行", "參與連署政務官發起之公投提案"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:38+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "507", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00210', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-113-b3f42868', 'sub-elementary-6f0ba476-01', NULL, 'single_choice', '為揚棄過往官方統治的觀念並彰顯地方特色，藉以提高政府效率，近年來政府施政強調「地方治理」的理 念。下列何者符合「地方治理」的精神？', '["新冠肺炎疫情期間，疫調、匡列與確診者足跡公布委由地方政府執行", "烏俄戰火蔓延之際，國內民眾募資援助烏克蘭，企業也跟進抵制俄國", "因應人口老化，衛生福利部與地方政府、民間單位推動一學區一日照中心", "地方政府採購新冠肺炎疫苗後交由中央疫情指揮中心統一調配"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:38+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "507", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00211', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-113-b3f42868', 'sub-elementary-6f0ba476-01', NULL, 'single_choice', '俄羅斯攻打烏克蘭之後，引發俄國國內的反戰聲浪，但總統普丁（VladimirPutin）一方面逮捕這些抗議人 士，另一方面透過立法宣布所有獨立報導都是犯罪行為。除關閉國內兩家獨立媒體外，諸多外國媒體也陸 續被迫停播或暫停在俄羅斯的採訪工作。若從民主國家統治正當性的角度檢視，前述報導凸顯俄羅斯的統 治缺乏何種正當性？', '["是否允許不同政黨的設立", "國家領導人是否定期改選", "是否保障公平開放的媒體", "總統是否由人民直接選出"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:38+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "507", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00212', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-113-b3f42868', 'sub-elementary-6f0ba476-01', NULL, 'single_choice', '德國為內閣制國家，2021年國會大選結果，席次率最高的三個政黨依序為：社民黨約占25.7%，基民盟約 占24.1%，綠黨約占14.8%；最後由社民黨的蕭茲（OlafScholz）擔任總理一職。依據德國的政府體制判 斷，下列分析何者正確？', '["社民黨可主導與其他政黨籌組聯合內閣或執政聯盟", "執政黨所提的法案若未通過，可移請國會進行覆議", "蕭茲擔任國家元首職務，屬不具政治實權的精神領袖", "行政機關不須對立法機關負責，落實分權制衡的原則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:38+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "507", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00213', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-113-b3f42868', 'sub-elementary-6f0ba476-01', NULL, 'single_choice', '甲選區舉行立法委員罷免案投票，該區選舉人總數為235,024人，依選舉委員會統計，投票率為41.93%， 同意票54,813張、不同意票43,340張。依公職人員選舉罷免法規定，此罷免案通過與否的主要理由為何？', '["罷免案通過，因同意罷免的票數多於不同意罷免的票數", "罷免案通過，因罷免案之投票率達選舉人總數四分之一", "罷免案不通過，因罷免案之投票率未達選舉人總數二分之一", "罷免案不通過，因同意票未達選舉人總數四分之一以上"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:38+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "507", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL)
